Javascript.validate:
var val = Services.getValue(TotalInvestAmnt.dataBinding);
var err = validateCurrencyValue(val, 99999999.99);
if( null == err )
{	Services.setValue(TotalInvestAmnt.dataBinding, WPU.formatToTwoDP(val));
}
return err;

